external_knowledge:
- "grand accommodations" refers to hotels;
- "majestic hotels" refers to hotel names;
- "combined room capacity" refers to the sum of total rooms;
- "threshold of 500" refers to the condition where the sum of total rooms is greater than 500;
- "palaces of rest" refers to hotels;
- "ranked by their abundance" refers to ordering by the count of hotels in descending order.

sql:
SELECT COUNT(hotel_id) 
FROM hotels 
WHERE star_rating > (SELECT AVG(star_rating) FROM hotels);

SELECT room_type, capacity, price_per_night
FROM room_types
ORDER BY price_per_night DESC;

SELECT hotel_name
FROM hotels
WHERE star_rating = (SELECT MAX(star_rating) FROM hotels);

SELECT hotel_name
FROM (
    SELECT hotel_name, (star_rating / total_rooms) AS avg_rating_per_room
    FROM hotels
) AS HotelRatingCTE
WHERE avg_rating_per_room = (
    SELECT MAX(avg_rating_per_room)
    FROM (
        SELECT (star_rating / total_rooms) AS avg_rating_per_room
        FROM hotels
    )
);
